Greedy best-fit insertion with fallback to new empty assign if all existing assigns fail, using sorted candidate list by marginal cost increase.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		idx       int
		marginal  float64
		success   bool
	}
	for jj := range oris {
		candidates := make([]cand, 0, dispatch.AssignsLen+1)
		bestIdx := -1
		bestMarginal := 1e100
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			prevCost := dispatch.Assigns[ii].Cost
			ok := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				dispatch.Assigns[ii].GenRoute()
				if dispatch.Assigns[ii].Cost >= 0 {
					marginal := dispatch.Assigns[ii].Cost - prevCost
					candidates = append(candidates, cand{idx: ii, marginal: marginal, success: true})
					if marginal < bestMarginal {
						bestMarginal = marginal
						bestIdx = ii
					}
				}
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			}
		}
		if bestIdx >= 0 {
			dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[bestIdx].GenRoute()
		} else {
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				ok := dispatch.Assigns[fallbackIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
				if ok {
					dispatch.Assigns[fallbackIdx].GenRoute()
					if dispatch.Assigns[fallbackIdx].Cost >= 0 {
						dispatch.AssignsLen++
					} else {
						dispatch.Assigns[fallbackIdx].RemoveShip(total_ship + jj)
						dispatch.Assigns[fallbackIdx].GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

